1407     computeKnownBits(I->getOperand(0), DemandedElts, Known2, Q, Depth + 1);
1408 
1409     Known = getKnownBitsFromAndXorOr(I, DemandedElts, Known2, Known, Q, Depth);
1410     break;
1411   case Instruction::Or:
