7677   if (const auto *A = dyn_cast<Argument>(V)) {
7678     if (A->hasAttribute(Attribute::NoUndef) ||
7679         A->hasAttribute(Attribute::Dereferenceable) ||
7680         A->hasAttribute(Attribute::DereferenceableOrNull))
7681       return true;
7682   }
7683 
7684   if (auto *C = dyn_cast<Constant>(V)) {
7685     if (isa<PoisonValue>(C))
7686       return !includesPoison(Kind);
7687 
7688     if (isa<UndefValue>(C))
7689       return !includesUndef(Kind);
7690 
7691     if (isa<ConstantInt>(C) || isa<GlobalVariable>(C) || isa<ConstantFP>(C) ||
7692         isa<ConstantPointerNull>(C) || isa<Function>(C))
7693       return true;
7694 
7695     if (C->getType()->isVectorTy()) {
7696       if (isa<ConstantExpr>(C)) {
7697         // Scalable vectors can use a ConstantExpr to build a splat.
7698         if (Constant *SplatC = C->getSplatValue())
7699           if (isa<ConstantInt>(SplatC) || isa<ConstantFP>(SplatC))
7700             return true;
7701       } else {
7702         if (includesUndef(Kind) && C->containsUndefElement())
7703           return false;
7704         if (includesPoison(Kind) && C->containsPoisonElement())
