7721       isa<Function>(StrippedV) || isa<ConstantPointerNull>(StrippedV))
7722     return true;
7723 
7724   auto OpCheck = [&](const Value *V) {
7725     return isGuaranteedNotToBeUndefOrPoison(V, AC, CtxI, DT, Depth + 1, Kind);
7726   };
7727 
7728   if (auto *Opr = dyn_cast<Operator>(V)) {
7729     // If the value is a freeze instruction, then it can never
7730     // be undef or poison.
7731     if (isa<FreezeInst>(V))
7732       return true;
7733 
7734     if (const auto *CB = dyn_cast<CallBase>(V)) {
7735       if (CB->hasRetAttr(Attribute::NoUndef) ||
